const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

console.log('\n=== Mon Deen - Patch complet ===\n');
const appDir = __dirname;
console.log('[OK] Dossier : ' + appDir);

const srcSrc = path.join(appDir, 'src', 'src');
if (fs.existsSync(srcSrc)) { fs.rmSync(srcSrc,{recursive:true,force:true}); console.log('[OK] src/src nettoye'); }

const files = {"src/App.jsx": "", "src/pages/Quran.jsx": "", "src/pages/Adhkar.jsx": "", "src/pages/DhikrCounter.jsx": "", "src/pages/Ramadan.jsx": "", "src/pages/Statistics.jsx": "", "src/pages/CerclePrivee.jsx": "", "src/pages/Zakat.jsx": "", "src/pages/Dashboard.jsx": ""};
for (const [rel, b64] of Object.entries(files)) {
  const dest = path.join(appDir, rel.replace(/\//g, path.sep));
  const dir = path.dirname(dest);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir,{recursive:true});
  fs.writeFileSync(dest, Buffer.from(b64,'base64'));
  console.log('[OK] ' + rel);
}

console.log('\nBuild...');
try { execSync('npm run build',{cwd:appDir,stdio:'inherit'}); console.log('[OK] Build OK'); }
catch(e) { console.log('[XX] Build echoue'); process.exit(1); }

console.log('\nGit...');
try {
  execSync('git add .',{cwd:appDir,stdio:'pipe'});
  try { execSync('git commit -m "Nav + nouvelles pages ' + new Date().toISOString().slice(0,10) + '"',{cwd:appDir,stdio:'pipe'}); console.log('[OK] Commit OK'); }
  catch(e) { console.log('[--] Rien a committer'); }
  execSync('git push origin main',{cwd:appDir,stdio:'pipe'});
  console.log('[OK] Push OK');
} catch(e) { console.log('[!!] Git : ' + e.message); }

console.log('\nVercel...');
try {
  execSync('vercel --prod --yes',{cwd:appDir,stdio:'inherit'});
  console.log('\n================================');
  console.log('DEPLOIEMENT TERMINE !');
  console.log('https://mon-deen-gules.vercel.app');
  console.log('================================');
} catch(e) { console.log('[!!] vercel login requis'); }
